// ── Toast Notification System ──
interface Toast {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

const ToastContext = createContext<{
  showToast: (type: Toast['type'], message: string) => void;
}>({ showToast: () => {} });

export const useToast = () => useContext(ToastContext);

const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
  return (
    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-2.5 pointer-events-none">
      {toasts.map((toast) => {
        const styles = {
          success: 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300',
          error: 'bg-red-500/15 border-red-500/30 text-red-300',
          info: 'bg-blue-500/15 border-blue-500/30 text-blue-300',
        };
        const icons = { success: '✓', error: '✕', info: 'ℹ' };
        return (
          <div
            key={toast.id}
            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-2xl shadow-black/40 animate-in slide-in-from-right fade-in duration-300 ${styles[toast.type]}`}
            onClick={() => onRemove(toast.id)}
          >
            <span className="text-sm font-bold">{icons[toast.type]}</span>
            <span className="text-sm font-medium">{toast.message}</span>
          </div>
        );
      })}
    </div>
  );
};

// Animated number hook for smooth credit transitions
const useAnimatedNumber = (value: number, duration = 600) => {
  const [display, setDisplay] = useState(value);
  const prevValue = useRef(value);
  useEffect(() => {
    if (prevValue.current === value) return;
    const start = prevValue.current;
    const diff = value - start;
    const startTime = performance.now();
    const animate = (now: number) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplay(Math.round(start + diff * eased));
      if (progress < 1) requestAnimationFrame(animate);
    };
    requestAnimationFrame(animate);
    prevValue.current = value;
  }, [value, duration]);
  return display;
};

