import React, { createContext, useContext } from 'react';

// ── Toast Notification System ──
export interface Toast {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

export const ToastContext = createContext<{
  showToast: (type: Toast['type'], message: string) => void;
}>({ showToast: () => {} });

export const useToast = () => useContext(ToastContext);

export const ToastContainer: React.FC<{ toasts: Toast[]; onRemove: (id: string) => void }> = ({ toasts, onRemove }) => {
  return (
    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-2.5 pointer-events-none">
      {toasts.map((toast) => {
        const styles = {
          success: 'bg-emerald-500/15 border-emerald-500/30 text-emerald-300',
          error: 'bg-red-500/15 border-red-500/30 text-red-300',
          info: 'bg-blue-500/15 border-blue-500/30 text-blue-300',
        };
        const icons = { success: '\u2713', error: '\u2715', info: '\u2139' };
        return (
          <div
            key={toast.id}
            className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border backdrop-blur-xl shadow-2xl shadow-black/40 animate-in slide-in-from-right fade-in duration-300 ${styles[toast.type]}`}
            onClick={() => onRemove(toast.id)}
          >
            <span className="text-sm font-bold">{icons[toast.type]}</span>
            <span className="text-sm font-medium">{toast.message}</span>
          </div>
        );
      })}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Search } from 'lucide-react';

const CommandPalettePanel: React.FC<{ onClose: () => void; onNavigate: (view: string) => void }> = ({ onClose, onNavigate }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setTimeout(() => inputRef.current?.focus(), 100);
  }, []);

  const commands = [
    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '\uD83D\uDD0D', category: 'Navigation' },
    { id: 'dashboard', label: 'Dashboard Pro', icon: '\uD83D\uDCCA', category: 'Navigation' },
    { id: 'projects', label: 'Monitoring AEO', icon: '\uD83D\uDCC8', category: 'Navigation' },
    { id: 'generative-tools', label: 'Outils G\u00e9n\u00e9ratifs', icon: '\u2728', category: 'Outils' },
    { id: 'smc-studio', label: 'SMC Studio', icon: '\u270F\uFE0F', category: 'Outils' },
    { id: 'content-writer', label: 'AI Content Writer', icon: '\uD83D\uDCDD', category: 'Outils' },
    { id: 'reputation', label: 'R\u00e9putation IA', icon: '\uD83D\uDEE1\uFE0F', category: 'Outils' },
    { id: 'source-of-truth', label: 'Source of Truth', icon: '\uD83D\uDCC4', category: 'Outils' },
    { id: 'schema-org', label: 'Schema.org Generator', icon: '\uD83D\uDD27', category: 'Outils' },
    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '\uD83E\uDD16', category: 'Outils' },
    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '\uD83D\uDC41\uFE0F', category: 'Outils' },
    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '\uD83D\uDCF0', category: 'Outils' },
    { id: 'ai-response-layer', label: 'AI Response Layer', icon: '\uD83E\uDDE9', category: 'Outils' },
    { id: 'llms-txt', label: 'G\u00e9n\u00e9rateur llms.txt', icon: '\uD83D\uDCCB', category: 'Outils' },
    { id: 'answer-first-audit', label: 'Audit Answer-First', icon: '\uD83C\uDFAF', category: 'Outils' },
    { id: 'ai-citation-simulator', label: 'Simulateur Citation IA', icon: '\uD83E\uDD16', category: 'Outils' },
    { id: 'eeat-builder', label: 'E-E-A-T Builder', icon: '\uD83C\uDFC6', category: 'Outils' },
    { id: 'ai-monitoring', label: 'Monitoring IA', icon: '\uD83D\uDCE1', category: 'Navigation' },
    { id: 'directory', label: 'Annuaire Index\u00e9', icon: '\uD83D\uDCDA', category: 'Navigation' },
    { id: 'recharge', label: 'GTO Gas Station', icon: '\u26FD', category: 'Navigation' },
    { id: 'clients', label: 'Base Clients', icon: '\uD83D\uDC65', category: 'Navigation' },
    { id: 'mission-orders', label: 'Ordres de Mission', icon: '\uD83D\uDCCB', category: 'Navigation' },
    { id: 'alerts', label: 'Alertes AEO', icon: '\uD83D\uDD14', category: 'Navigation' },
    { id: 'account', label: 'Compte & Plan', icon: '\uD83D\uDC64', category: 'Navigation' },
    { id: 'affiliation', label: 'Programme Partenaire', icon: '\uD83E\uDD1D', category: 'Navigation' },
  ];

  const filtered = query
    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
    : commands;

  const grouped = filtered.reduce((acc, cmd) => {
    if (!acc[cmd.category]) acc[cmd.category] = [];
    acc[cmd.category].push(cmd);
    return acc;
  }, {} as Record<string, typeof commands>);

  // Highlight matched text in label
  const highlightMatch = (label: string) => {
    if (!query) return <span>{label}</span>;
    const lowerLabel = label.toLowerCase();
    const lowerQuery = query.toLowerCase();
    const idx = lowerLabel.indexOf(lowerQuery);
    if (idx === -1) return <span>{label}</span>;
    return (
      <span>
        {label.slice(0, idx)}
        <span className="text-purple-400 font-semibold">{label.slice(idx, idx + query.length)}</span>
        {label.slice(idx + query.length)}
      </span>
    );
  };

  return (
    <div
      className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden"
      onClick={(e) => e.stopPropagation()}
    >
      <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
        <Search size={18} className="text-gray-500 shrink-0" />
        <input
          ref={inputRef}
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Rechercher une page, un outil..."
          className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
        />
        <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">ESC</kbd>
      </div>
      <div className="max-h-[340px] overflow-y-auto py-2">
        {Object.keys(grouped).length === 0 ? (
          <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun r&eacute;sultat pour &ldquo;{query}&rdquo;</div>
        ) : (
          Object.entries(grouped).map(([category, cmds]) => (
            <div key={category}>
              <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
              {cmds.map((cmd) => (
                <button
                  key={cmd.id}
                  onClick={() => onNavigate(cmd.id)}
                  className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
                >
                  <span className="text-base">{cmd.icon}</span>
                  <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{highlightMatch(cmd.label)}</span>
                </button>
              ))}
            </div>
          ))
        )}
      </div>
      <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
        <div className="flex items-center gap-3">
          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">&uarr;&darr;</kbd> naviguer</span>
          <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">&crarr;</kbd> ouvrir</span>
        </div>
        <span>CitedBy.ai</span>
      </div>
    </div>
  );
};

