                          className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-gray-300 hover:text-white hover:bg-white/[0.04] transition-colors"
                        >
                          <action.icon size={15} className="text-purple-400" />
                          {action.label}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              {/* Bell notification with dropdown */}
              <div className="relative" ref={notifRef as React.RefObject<HTMLDivElement>}>
                <button
                  onClick={() => setIsNotifOpen(!isNotifOpen)}
                  className="relative w-9 h-9 rounded-full bg-white/[0.04] border border-white/[0.06] flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/[0.08] transition-colors"
                  title="Notifications"
                >
                  <Bell size={16} />
                  {unreadCount > 0 && (
                    <span className="absolute -top-0.5 -right-0.5 w-3 h-3 bg-amber-500 rounded-full border-2 border-[#0e0e18]"></span>
                  )}
                </button>

                {isNotifOpen && (
                  <div className="absolute right-0 top-full mt-2 w-[380px] max-w-[380px] bg-[#13131d] border border-white/[0.08] rounded-2xl shadow-2xl z-50 overflow-hidden">
                    {/* Header */}
                    <div className="flex items-center justify-between px-5 py-4 border-b border-white/[0.06]">
                      <div className="flex items-center gap-2.5">
                        <span className="text-white font-semibold text-sm">Notifications</span>
                        {unreadCount > 0 && (
                          <span className="px-2 py-0.5 rounded-full bg-amber-500/15 text-amber-400 text-xs font-bold">
                            {unreadCount}
                          </span>
                        )}
                      </div>
                      <button
                        onClick={() => setIsNotifOpen(false)}
                        className="text-gray-500 hover:text-white transition-colors"
                      >
                        <X size={14} />
                      </button>
                    </div>

                    {/* Notification list */}
                    <div className="max-h-[360px] overflow-y-auto">
                      {notifications.map((notif) => {
                        const iconMap = {
                          critical: { icon: AlertCircle, color: 'text-red-400', bg: 'bg-red-500/10' },
                          warning: { icon: AlertTriangle, color: 'text-amber-400', bg: 'bg-amber-500/10' },
                          info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10' },
                          success: { icon: CheckCircle, color: 'text-emerald-400', bg: 'bg-emerald-500/10' },
                        };
                        const { icon: Icon, color, bg } = iconMap[notif.type];
                        return (
                          <div
                            key={notif.id}
                            className="flex items-start gap-3 px-5 py-3.5 hover:bg-white/[0.03] transition-colors cursor-pointer border-b border-white/[0.04] last:border-b-0"
                          >
                            <div className={`w-8 h-8 rounded-lg ${bg} flex items-center justify-center flex-shrink-0 mt-0.5`}>
                              <Icon size={15} className={color} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className={`text-sm leading-snug ${notif.unread ? 'text-white font-medium' : 'text-gray-400'}`}>
                                {notif.title}
                              </p>
                              <p className="text-xs text-gray-500 mt-1">{notif.time}</p>
                            </div>
                            {notif.unread && (
                              <div className="w-2 h-2 rounded-full bg-purple-500 flex-shrink-0 mt-2"></div>
                            )}
                          </div>
                        );
                      })}
                    </div>

                    {/* Footer */}
                    <div className="border-t border-white/[0.06] px-5 py-3">
                      <button
                        onClick={() => { setIsNotifOpen(false); navigateTo('alerts'); }}
                        className="w-full text-center text-sm text-purple-400 hover:text-purple-300 font-medium transition-colors"
                      >
                        Voir toutes les alertes
                      </button>
                    </div>
                  </div>
                )}
              </div>
              {/* Credits badge with progress bar */}
              <button
                onClick={() => navigateTo('recharge')}
                className="hidden md:flex flex-col items-stretch px-3.5 py-1.5 rounded-full bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500/20 transition-colors group"
                title="Recharger GTO Gas"
              >
                <div className="flex items-center gap-2">
                  <Fuel size={14} className="text-amber-400" />
                  <span className="text-sm font-bold text-amber-400">{animatedCredits.toLocaleString()}</span>
                  <span className="text-xs text-amber-400/70 font-medium">Credits</span>
                </div>
                <div className="w-full h-1 bg-amber-900/30 rounded-full mt-1 overflow-hidden">
                  <div
                    className="h-full rounded-full transition-all duration-500"
                    style={{
                      width: `${Math.min(100, (user.credits / (user.plan === 'enterprise' ? 1000 : user.plan === 'pro' ? 200 : 50)) * 100)}%`,
                      background: user.credits <= 10 ? '#ef4444' : 'linear-gradient(90deg, #f59e0b, #d97706)'
                    }}
                  />
                </div>
              </button>
              <div className="relative" ref={profileRef as React.RefObject<HTMLDivElement>}>
                <button
                  onClick={() => setIsProfileOpen(!isProfileOpen)}
                  className="flex items-center gap-2.5 group"
                >
                  <div className="text-right hidden sm:block">
                    <p className="text-sm font-semibold text-white leading-none group-hover:text-purple-400 transition-colors">{user.name}</p>
                    <div className="flex items-center justify-end gap-1.5 mt-0.5">
                      <p className="text-[10px] text-gray-500 uppercase tracking-wider">{user.plan === 'free' ? 'Admin' : user.plan.toUpperCase()}</p>
                      {sessionMinutes > 0 && (
                        <span className="flex items-center gap-0.5 text-[10px] text-gray-600">
                          <Clock size={8} />
                          {sessionMinutes >= 60 ? `${Math.floor(sessionMinutes / 60)}h${String(sessionMinutes % 60).padStart(2, '0')}` : `${sessionMinutes}m`}
                        </span>
                      )}
                    </div>
                  </div>
                  <div className="w-9 h-9 rounded-full bg-gradient-to-br from-purple-500/20 to-violet-500/20 border border-purple-500/30 text-purple-300 text-sm font-bold flex items-center justify-center group-hover:border-purple-400/50 transition-colors">
                    {user.name.charAt(0).toUpperCase()}
                  </div>
                </button>

                {isProfileOpen && (
                  <div className="absolute right-0 top-full mt-2 w-[260px] bg-[#13131d] border border-white/[0.08] rounded-2xl shadow-2xl z-50 overflow-hidden">
                    <div className="px-5 py-4 border-b border-white/[0.06]">
                      <p className="text-sm font-semibold text-white">{user.name}</p>
                      <p className="text-xs text-gray-500 mt-0.5">{user.email || 'admin@citedby.ai'}</p>
                      <div className="flex items-center gap-2 mt-2.5">
                        <span className="px-2 py-0.5 rounded-full bg-purple-500/15 text-purple-400 text-[10px] font-bold uppercase">{user.plan === 'free' ? 'Starter' : user.plan}</span>
                        <span className="px-2 py-0.5 rounded-full bg-amber-500/15 text-amber-400 text-[10px] font-bold">{user.credits} Credits</span>
                      </div>
                    </div>
                    <div className="py-1.5">
                      <button onClick={() => { setIsProfileOpen(false); navigateTo('account'); }} className="w-full flex items-center gap-3 px-5 py-2.5 text-sm text-gray-300 hover:text-white hover:bg-white/[0.04] transition-colors">
                        <UserIcon size={15} className="text-gray-500" /> Mon Compte
                      </button>
                      <button onClick={() => { setIsProfileOpen(false); navigateTo('recharge'); }} className="w-full flex items-center gap-3 px-5 py-2.5 text-sm text-gray-300 hover:text-white hover:bg-white/[0.04] transition-colors">
                        <Fuel size={15} className="text-gray-500" /> Recharger Credits
                      </button>
                      <button onClick={() => { setIsProfileOpen(false); onOpenCommandPalette(); }} className="w-full flex items-center gap-3 px-5 py-2.5 text-sm text-gray-300 hover:text-white hover:bg-white/[0.04] transition-colors">
                        <Search size={15} className="text-gray-500" /> Recherche rapide
                        <kbd className="ml-auto px-1.5 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded font-mono">⌘K</kbd>
                      </button>
                    </div>
                    <div className="border-t border-white/[0.06] py-1.5">
                      <button onClick={() => { setIsProfileOpen(false); onLogout(); }} className="w-full flex items-center gap-3 px-5 py-2.5 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/[0.05] transition-colors">
                        <LogOut size={15} /> Déconnexion
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="flex items-center gap-3">
              <LanguageSelector compact />
              <button
                onClick={() => navigateTo('login')}
                className="btn-gradient text-sm !py-2 !px-5"
              >
                {t.nav.login}
              </button>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import {
  Home as HomeIcon, Search, LayoutDashboard, Activity, Sparkles,
  BookOpen, Fuel, Share2, Users, FileText, Bell, UserCircle, BarChart3
} from 'lucide-react';
import { useTranslation } from '../i18n';

interface SidebarProps {
  currentView: string;
  navigateTo: (view: string) => void;
  isSidebarCollapsed: boolean;
  isMobileMenuOpen: boolean;
  setIsMobileMenuOpen: (v: boolean) => void;
}

const NavItem = ({ view, label, icon: Icon, onClick, active, collapsed, currentView, navigateTo }: {
  view?: string;
  label: string;
  icon: React.ElementType;
  onClick?: () => void;
  active?: boolean;
  collapsed?: boolean;
  currentView: string;
  navigateTo: (view: string) => void;
}) => {
  const handleClick = onClick ? onClick : () => view && navigateTo(view);
  const isActive = active !== undefined ? active : (view && currentView === view);

  if (collapsed) {
    return (
      <div className="relative group">
        <button
          onClick={handleClick}
          className={`w-full flex items-center justify-center py-2.5 rounded-xl transition-all duration-200 ${
            isActive
              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
              : 'text-gray-400 hover:text-white hover:bg-white/[0.06]'
          }`}
        >
          <Icon size={18} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
        </button>
        <div className="absolute left-full top-1/2 -translate-y-1/2 ml-3 px-3 py-1.5 bg-[#1a1d21] border border-white/[0.1] rounded-lg shadow-xl text-xs font-medium text-white whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-200 z-50">
          {label}
          <div className="absolute right-full top-1/2 -translate-y-1/2 w-0 h-0 border-t-[5px] border-t-transparent border-b-[5px] border-b-transparent border-r-[5px] border-r-[#1a1d21]" />
        </div>
      </div>
    );
  }

  return (
    <button
      onClick={handleClick}
      className={`relative w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[13.5px] transition-all duration-200 group font-sans overflow-hidden ${
        isActive
          ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white font-semibold shadow-lg shadow-purple-900/30'
          : 'text-gray-400 hover:text-white hover:bg-white/[0.06] font-medium'
      }`}
    >
      {/* Animated active indicator bar */}
      <div className={`absolute left-0 top-1/2 -translate-y-1/2 w-[3px] rounded-full bg-white transition-all duration-300 ${isActive ? 'h-5 opacity-100' : 'h-0 opacity-0'}`} />
      <Icon size={17} className={`shrink-0 ${isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"}`} />
      <span className="truncate transition-opacity duration-200">{label}</span>
    </button>
  );
};

const Sidebar: React.FC<SidebarProps> = ({
  currentView,
  navigateTo,
  isSidebarCollapsed,
  isMobileMenuOpen,
  setIsMobileMenuOpen,
}) => {
  const { t } = useTranslation();

  const navItemProps = { currentView, navigateTo };

  return (
    <>
      {/* Mobile overlay */}
      <div
        className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
          isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        onClick={() => setIsMobileMenuOpen(false)}
      />
      {/* Mobile sidebar */}
      <aside
        id="mobile-sidebar-menu"
        className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#0e0e18] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
          isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
        }`}
      >
        <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
          <div className="bg-[#13131d]/80 border border-white/[0.06] rounded-2xl p-3 space-y-1">
            <NavItem label={t.nav.home} icon={HomeIcon} view="home" {...navItemProps} />
            <NavItem label={t.nav.newAudit} icon={Search} view="analyze" {...navItemProps} />
            <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" {...navItemProps} />
            <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} {...navItemProps} />
            <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking', 'blog-optimizer', 'ai-response-layer', 'llms-txt', 'answer-first-audit', 'ai-citation-simulator', 'eeat-builder'].includes(currentView)} {...navItemProps} />
            <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} {...navItemProps} />
            <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" {...navItemProps} />
            <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" {...navItemProps} />
            <NavItem label={t.nav.baseClients} icon={Users} view="clients" {...navItemProps} />
            <NavItem label={t.nav.missionOrders} icon={FileText} view="mission-orders" {...navItemProps} />
            <NavItem label={t.nav.alertsAEO} icon={Bell} view="alerts" {...navItemProps} />

            <div className="my-4 border-t border-white/[0.08] mx-4"></div>

            <NavItem label={t.nav.accountPlan} icon={UserCircle} view="account" {...navItemProps} />
          </div>
        </div>
      </aside>

      {/* Desktop sidebar */}
      <aside className={`hidden md:flex flex-col py-4 sticky top-14 h-[calc(100vh-3.5rem)] overflow-y-auto shrink-0 transition-[width,padding] duration-300 ease-in-out ${
        isSidebarCollapsed ? 'w-[68px] px-2' : 'w-64 px-3'
      }`}>
        <div className={`bg-[#13131d]/80 border border-white/[0.06] rounded-2xl shadow-lg overflow-y-auto custom-scrollbar ${
          isSidebarCollapsed ? 'p-1.5 space-y-0.5' : 'p-3 space-y-1'
        }`}>
           {/* PRINCIPAL */}
           {!isSidebarCollapsed && <div className="px-4 pt-2 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Principal</span></div>}
           {isSidebarCollapsed && <div className="my-1" />}
           <NavItem label={t.nav.home} icon={HomeIcon} view="home" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.newAudit} icon={Search} view="analyze" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label="Monitoring IA" icon={BarChart3} view="ai-monitoring" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />

           {/* OUTILS */}
           {!isSidebarCollapsed && <div className="px-4 pt-5 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Outils</span></div>}
           {isSidebarCollapsed && <div className="my-2 mx-3 border-t border-white/[0.06]" />}
           <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking', 'blog-optimizer', 'ai-response-layer', 'llms-txt', 'answer-first-audit', 'ai-citation-simulator', 'eeat-builder'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} collapsed={isSidebarCollapsed} {...navItemProps} />

           {/* GESTION */}
           {!isSidebarCollapsed && <div className="px-4 pt-5 pb-1.5"><span className="text-[10px] font-bold text-gray-600 uppercase tracking-wider">Gestion</span></div>}
           {isSidebarCollapsed && <div className="my-2 mx-3 border-t border-white/[0.06]" />}
           <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.baseClients} icon={Users} view="clients" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.missionOrders} icon={FileText} view="mission-orders" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.alertsAEO} icon={Bell} view="alerts" collapsed={isSidebarCollapsed} {...navItemProps} />
           <NavItem label={t.nav.accountPlan} icon={UserCircle} view="account" collapsed={isSidebarCollapsed} {...navItemProps} />
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

import React from 'react';
import {
  LayoutDashboard, FolderOpen, ScanLine, User as UserIcon
} from 'lucide-react';
import { useTranslation } from '../i18n';

interface MobileBottomNavProps {
  currentView: string;
  navigateTo: (view: string) => void;
  isMobileMenuOpen: boolean;
}

const MobileBottomNav: React.FC<MobileBottomNavProps> = ({ currentView, navigateTo, isMobileMenuOpen }) => {
  const { t } = useTranslation();

  return (
    <div className={`md:hidden fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-lg border-t border-white/[0.06] z-50 pb-safe transition-opacity duration-200 ${
      isMobileMenuOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'
    }`}>
      <div className="flex justify-around items-center h-16 px-2 relative">
        {[
          { view: 'dashboard', icon: LayoutDashboard, label: t.nav.dash },
          { view: 'projects', icon: FolderOpen, label: t.nav.projects },
          { view: 'analyze', icon: ScanLine, label: t.nav.audit },
          { view: 'account', icon: UserIcon, label: t.nav.account }
        ].map((item) => {
          const isActive = currentView === item.view;
          return (
            <button
              key={item.view}
              onClick={() => navigateTo(item.view)}
              className={`relative flex flex-col items-center justify-center w-full h-full space-y-1 transition-all duration-200 ${
                isActive ? 'text-primary' : 'text-gray-500'
              }`}
            >
              {isActive && (
                <div className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-0.5 rounded-full bg-gradient-to-r from-purple-500 to-violet-500" />
              )}
              <item.icon size={20} className={`transition-transform duration-200 ${isActive ? 'fill-primary/20 scale-110' : ''}`} />
              <span className={`text-[10px] font-medium transition-all duration-200 ${isActive ? 'font-bold' : ''}`}>{item.label}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default MobileBottomNav;

